A production-ready pipeline for ingesting enterprise documents (PDFs, Word docs, web pages, databases) into the ruvector knowledge base with chunking, metadata extraction, and deduplication.

## Supported Document Types and Extraction Methods

```javascript
// Document type routing
const EXTRACTORS = {
  '.pdf':  extractPDF,
  '.docx': extractWord,
  '.xlsx': extractExcel,
  '.txt':  extractText,
  '.md':   extractMarkdown,
  '.html': extractHTML,
  '.csv':  extractCSV,
};
```

## Core Ingestion Pipeline

```javascript
// /scripts/ingest-enterprise-docs.mjs
import { readFileSync, readdirSync, statSync } from 'fs';
import { extname, join } from 'path';
import pg from 'pg';
import pdfParse from 'pdf-parse';
import mammoth from 'mammoth';

const pool = new pg.Pool({
  host: process.env.DB_HOST || 'localhost',
  port: process.env.DB_PORT || 5435,
  database: process.env.DB_NAME || 'ruvector_kb',
  user: process.env.DB_USER || 'ruvector',
  // Password via ~/.pgpass
});

const OLLAMA_URL = process.env.OLLAMA_URL || 'http://localhost:11434';
const EMBED_MODEL = 'nomic-embed-text';
const CHUNK_SIZE = 1500;  // characters per chunk
const CHUNK_OVERLAP = 200;  // overlap between chunks

// Generate embedding via local Ollama
async function embed(text) {
  const res = await fetch(`${OLLAMA_URL}/api/embeddings`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: EMBED_MODEL, prompt: text })
  });
  const data = await res.json();
  return data.embedding;
}

// Smart text chunking with sentence boundary detection
function chunkText(text, chunkSize = CHUNK_SIZE, overlap = CHUNK_OVERLAP) {
  const sentences = text.match(/[^.!?]+[.!?]+/g) || [text];
  const chunks = [];
  let current = '';

  for (const sentence of sentences) {
    if (current.length + sentence.length > chunkSize && current.length > 0) {
      chunks.push(current.trim());
      // Keep overlap: last N characters of current chunk
      current = current.slice(-overlap) + ' ' + sentence;
    } else {
      current += ' ' + sentence;
    }
  }

  if (current.trim()) chunks.push(current.trim());
  return chunks.filter(c => c.length > 50);  // Skip tiny chunks
}

// Extract text from PDF
async function extractPDF(filePath) {
  const buffer = readFileSync(filePath);
  const data = await pdfParse(buffer);
  return {
    text: data.text,
    metadata: {
      pages: data.numpages,
      info: data.info,
    }
  };
}

// Extract text from DOCX
async function extractWord(filePath) {
  const result = await mammoth.extractRawText({ path: filePath });
  return { text: result.value, metadata: {} };
}

// Main ingestion function
async function ingestDocument(filePath, options = {}) {
  const {
    category = 'general',
    tags = [],
    source_type = 'document',
  } = options;

  const ext = extname(filePath).toLowerCase();
  const extractor = {
    '.pdf': extractPDF,
    '.docx': extractWord,
    '.txt': async (p) => ({ text: readFileSync(p, 'utf8'), metadata: {} }),
  }[ext];

  if (!extractor) {
    console.warn(`No extractor for ${ext}, skipping ${filePath}`);
    return null;
  }

  const { text, metadata } = await extractor(filePath);
  const title = options.title || filePath.split('/').pop().replace(ext, '');

  // Check for existing document (deduplication)
  const contentHash = require('crypto').createHash('md5').update(text).digest('hex');
  const existing = await pool.query(
    'SELECT id FROM knowledge_base WHERE content_hash = $1',
    [contentHash]
  );

  if (existing.rows.length > 0) {
    console.log(`Skipping duplicate: ${title}`);
    return existing.rows[0].id;
  }

  // Embed the full document for top-level search
  const fullEmbedding = await embed(`${title}\n\n${text.slice(0, 3000)}`);

  // Insert main document record
  const doc = await pool.query(
    `INSERT INTO knowledge_base (title, content, source, source_type, category, tags, embedding, metadata)
     VALUES ($1, $2, $3, $4, $5, $6, $7::vector, $8)
     RETURNING id`,
    [title, text, filePath, source_type, category, tags,
     JSON.stringify(fullEmbedding), JSON.stringify({ ...metadata, file_path: filePath })]
  );

  const docId = doc.rows[0].id;

  // Chunk and index for detailed search
  const chunks = chunkText(text);
  console.log(`  Indexing ${chunks.length} chunks...`);

  for (let i = 0; i < chunks.length; i++) {
    const chunkEmbedding = await embed(chunks[i]);
    await pool.query(
      `INSERT INTO document_chunks (document_id, chunk_index, chunk_content, embedding)
       VALUES ($1, $2, $3, $4::vector)`,
      [docId, i, chunks[i], JSON.stringify(chunkEmbedding)]
    );

    // Rate limit to avoid overwhelming Ollama
    if (i % 10 === 0) await new Promise(r => setTimeout(r, 100));
  }

  console.log(`Ingested: ${title} (${chunks.length} chunks, ID: ${docId})`);
  return docId;
}

// Batch ingest a directory
async function ingestDirectory(dirPath, options = {}) {
  const files = readdirSync(dirPath);
  let success = 0, skipped = 0, failed = 0;

  for (const file of files) {
    const fullPath = join(dirPath, file);
    if (statSync(fullPath).isDirectory()) continue;

    try {
      const result = await ingestDocument(fullPath, options);
      if (result) success++; else skipped++;
    } catch (err) {
      console.error(`Failed: ${file} - ${err.message}`);
      failed++;
    }
  }

  console.log(`\nBatch complete: ${success} ingested, ${skipped} skipped, ${failed} failed`);
}

// CLI usage
const [,, targetPath, ...args] = process.argv;
const options = {
  category: args.find(a => a.startsWith('--category='))?.split('=')[1] || 'general',
  tags: args.find(a => a.startsWith('--tags='))?.split('=')[1]?.split(',') || [],
};

if (statSync(targetPath).isDirectory()) {
  ingestDirectory(targetPath, options).catch(console.error);
} else {
  ingestDocument(targetPath, options).catch(console.error);
}
```

## Usage Examples

```bash
# Ingest a single PDF
node scripts/ingest-enterprise-docs.mjs /docs/policy-manual.pdf \
  --category=hr-policies \
  --tags=policy,hr,2024

# Ingest entire directory
node scripts/ingest-enterprise-docs.mjs /docs/contracts/ \
  --category=vendor-contracts \
  --tags=contract,legal

# Verify ingestion
docker exec ruvector-postgres psql -U ruvector -d ruvector_kb -c \
  "SELECT category, count(*), sum(length(content)) as total_chars FROM knowledge_base GROUP BY category;"
```

## Monitoring Ingestion Progress

```sql
-- Check ingestion status
SELECT 
  count(*) as total_documents,
  count(embedding) as embedded,
  count(*) - count(embedding) as pending_embedding,
  sum(length(content)) / 1048576 as total_mb
FROM knowledge_base;

-- Recently ingested
SELECT title, category, array_length(tags,1) as tag_count, created_at
FROM knowledge_base
ORDER BY created_at DESC
LIMIT 20;
```
